    19→public static class OrderingEndpoints
    20→{
    21→    public static IEndpointRouteBuilder MapOrderingEndpoints(this IEndpointRouteBuilder endpoints)
    22→    {
    23→        RouteGroupBuilder group = endpoints.MapGroup("/api/ordering")
    24→            .WithTags("Ordering");
    25→
    26→        group.MapPost("/checkout", Checkout)
    27→            .WithName("Checkout")
