    32→        group.MapPost("/orders/{id:guid}/pay", SimulatePayment)
    33→            .WithName("SimulatePayment")
    34→            .WithSummary("Simulate payment for an order (dev/test)")
    35→            .Produces<SimulatePaymentResult>()
    36→            .ProducesProblem(StatusCodes.Status404NotFound);
    37→
    38→        group.MapGet("/orders/{id:guid}", GetOrderById)
    39→            .WithName("GetOrderById")
    40→            .WithSummary("Get order details by ID")
    41→            .Produces<OrderDto>()
    42→            .ProducesProblem(StatusCodes.Status404NotFound);
