    47→            .Produces<OrderListDto>();
    48→
    49→        group.MapGet("/orders", GetAllOrders)
    50→            .WithName("GetAllOrders")
    51→            .WithSummary("Get all orders (admin, paginated)")
    52→            .Produces<OrderListDto>();
    53→
    54→        group.MapGet("/dashboard", GetDashboard)
    55→            .WithName("GetOrderDashboard")
    56→            .WithSummary("Get order dashboard statistics (admin)")
    57→            .Produces<OrderDashboardDto>();
    58→
    59→        group.MapPatch("/orders/{id:guid}/status", UpdateOrderStatus)
    60→            .WithName("UpdateOrderStatus")
    61→            .WithSummary("Update order status (admin: Ship or Deliver)")
    62→            .Produces(StatusCodes.Status204NoContent)
    63→            .ProducesProblem(StatusCodes.Status404NotFound)
    64→            .ProducesProblem(StatusCodes.Status422UnprocessableEntity)
    65→            .ProducesValidationProblem();
    66→
    67→        return endpoints;
    68→    }
